    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool showForm;
    private ShipmentDto editingShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        editingShipment = new ShipmentDto
        {
            Status = "Pending",
            ShippedDate = DateTime.Today,
            EstimatedDelivery = DateTime.Today.AddDays(5)
        };
        showForm = true;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        editingShipment = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            CustomerEmail = shipment.CustomerEmail,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            ActualDelivery = shipment.ActualDelivery,
            Notes = shipment.Notes
        };
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (editingShipment.Id == 0)
        {
            var created = await ShipmentService.CreateShipmentAsync(editingShipment);
            shipments!.Add(created);
        }
        else
        {
            var updated = await ShipmentService.UpdateShipmentAsync(editingShipment);
            var index = shipments!.FindIndex(s => s.Id == updated.Id);
            if (index >= 0) shipments[index] = updated;
        }
        showForm = false;
    }

    private void CancelForm() => showForm = false;

    private static string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "In Transit" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}
