```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(s => MapToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<List<ShipmentDto>> GetShipmentsForCustomerAsync()
    {
        // This is called from the API endpoint which provides the email filter
        // When called directly on server during prerender, returns empty
        return [];
    }

    public Task<List<ShipmentDto>> GetShipmentsForCustomerAsync(string email)
    {
        return db.Shipments
            .Where(s => s.CustomerEmail == email)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = dto.TrackingNumber,
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = dto.Status,
            CustomerEmail = dto.CustomerEmail,
            ShippedDate = dto.ShippedDate,
            EstimatedDelivery = dto.EstimatedDelivery,
            ActualDelivery = dto.ActualDelivery,
            Notes = dto.Notes
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    public async Task<ShipmentDto> UpdateShipmentAsync(ShipmentDto dto)
    {
        var shipment = await db.Shipments.FindAsync(dto.Id)
            ?? throw new InvalidOperationException("Shipment not found");
        shipment.Origin = dto.Origin;
        shipment.Destination = dto.Destination;
        shipment.Status = dto.Status;
        shipment.CustomerEmail = dto.CustomerEmail;
        shipment.EstimatedDelivery = dto.EstimatedDelivery;
        shipment.ActualDelivery = dto.ActualDelivery;
        shipment.Notes = dto.Notes;
        await db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CustomerEmail = s.CustomerEmail,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        Notes = s.Notes
    };
}
```

### 7. API Endpoints

Create `ShipmentTracker/ShipmentEndpoints.cs`:
```csharp
using System.Security.Claims;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Services;

namespace ShipmentTracker;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (ShipmentServerService service) =>
        {
            var shipments = await service.GetAllShipmentsAsync();
            return Results.Ok(shipments);
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ShipmentServerService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).AllowAnonymous();

        group.MapGet("/my", async (ClaimsPrincipal user, ShipmentServerService service) =>
        {
            var email = user.FindFirstValue(ClaimTypes.Email) ?? user.FindFirstValue(ClaimTypes.Name);
            if (string.IsNullOrEmpty(email)) return Results.Unauthorized();
            var shipments = await service.GetShipmentsForCustomerAsync(email);
            return Results.Ok(shipments);
        });

        group.MapPost("/", async (ShipmentDto dto, ShipmentServerService service) =>
        {
            if (string.IsNullOrWhiteSpace(dto.TrackingNumber))
                dto.TrackingNumber = Guid.NewGuid().ToString("N")[..12].ToUpper();
            var created = await service.CreateShipmentAsync(dto);
            return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
        });

        group.MapPut("/{id:int}", async (int id, ShipmentDto dto, ShipmentServerService service) =>
        {
            dto.Id = id;
            var updated = await service.UpdateShipmentAsync(dto);
            return Results.Ok(updated);
        });
    }
}
```

