using System.Security.Claims;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Services;

namespace ShipmentTracker;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (ShipmentServerService service) =>
        {
            var shipments = await service.GetAllShipmentsAsync();
            return Results.Ok(shipments);
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ShipmentServerService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).AllowAnonymous();

        group.MapGet("/my", async (ClaimsPrincipal user, ShipmentServerService service) =>
        {
            var email = user.FindFirstValue(ClaimTypes.Email) ?? user.FindFirstValue(ClaimTypes.Name);
            if (string.IsNullOrEmpty(email)) return Results.Unauthorized();
            var shipments = await service.GetShipmentsForCustomerAsync(email);
            return Results.Ok(shipments);
        });

        group.MapPost("/", async (ShipmentDto dto, ShipmentServerService service) =>
        {
            if (string.IsNullOrWhiteSpace(dto.TrackingNumber))
                dto.TrackingNumber = Guid.NewGuid().ToString("N")[..12].ToUpper();
            var created = await service.CreateShipmentAsync(dto);
            return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
        });

        group.MapPut("/{id:int}", async (int id, ShipmentDto dto, ShipmentServerService service) =>
        {
            dto.Id = id;
            var updated = await service.UpdateShipmentAsync(dto);
            return Results.Ok(updated);
        });
    }
}
