@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Board</PageTitle>

<h1>Dispatch Board</h1>

<div class="mb-3 d-flex gap-2">
    <input type="text" class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    <select class="form-select w-auto" @bind="statusFilter">
        <option value="">All Statuses</option>
        <option value="Pending">Pending</option>
        <option value="In Transit">In Transit</option>
        <option value="Delivered">Delivered</option>
        <option value="Delayed">Delayed</option>
    </select>
    <button class="btn btn-success text-nowrap" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingShipment.Id == 0 ? "Create Shipment" : "Edit Shipment")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="editingShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="editingShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer email" @bind="editingShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <select class="form-select" @bind="editingShipment.Status">
                        <option value="Pending">Pending</option>
                        <option value="In Transit">In Transit</option>
                        <option value="Delivered">Delivered</option>
                        <option value="Delayed">Delayed</option>
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label small">Shipped Date</label>
                    <input type="date" class="form-control" @bind="editingShipment.ShippedDate" />
                </div>
                <div class="col-md-3">
                    <label class="form-label small">Est. Delivery</label>
                    <input type="date" class="form-control" @bind="editingShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-6">
                    <input class="form-control" placeholder="Notes" @bind="editingShipment.Notes" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="SaveShipment">Save</button>
                <button class="btn btn-outline-secondary" @onclick="CancelForm">Cancel</button>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Customer</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><code>@s.TrackingNumber</code></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@s.CustomerEmail</td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td><button class="btn btn-sm btn-outline-primary" @onclick="() => EditShipment(s)">Edit</button></td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool showForm;
    private ShipmentDto editingShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        editingShipment = new ShipmentDto
        {
            Status = "Pending",
            ShippedDate = DateTime.Today,
            EstimatedDelivery = DateTime.Today.AddDays(5)
        };
        showForm = true;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        editingShipment = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            CustomerEmail = shipment.CustomerEmail,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            ActualDelivery = shipment.ActualDelivery,
            Notes = shipment.Notes
        };
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (editingShipment.Id == 0)
        {
            var created = await ShipmentService.CreateShipmentAsync(editingShipment);
            shipments!.Add(created);
        }
        else
        {
            var updated = await ShipmentService.UpdateShipmentAsync(editingShipment);
            var index = shipments!.FindIndex(s => s.Id == updated.Id);
            if (index >= 0) shipments[index] = updated;
        }
        showForm = false;
    }

    private void CancelForm() => showForm = false;

    private static string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "In Transit" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

