@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchNumber = string.Empty;
    private string lastSearched = string.Empty;
    private ShipmentDto? shipment;
    private bool searching;
    private bool searched;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchNumber = TrackingNumber;
            await Search();
        }
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(searchNumber)) return;
        searching = true;
        searched = false;
        shipment = null;
        StateHasChanged();

        lastSearched = searchNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        searching = false;
        searched = true;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await Search();
    }

    private static string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "In Transit" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}
